import React, { useEffect, useRef, useState } from 'react';

const VideoFrame = ({ src, onError }) => {
  const containerRef = useRef(null);
  const [firstClickUsed, setFirstClickUsed] = useState(false);
  const [showPlayButton, setShowPlayButton] = useState(true);

  useEffect(() => {
    if (src && containerRef.current) {
      const frame = document.createElement('iframe');

      frame.src = src;
      frame.width = '100%';
      frame.height = '100%';
      frame.allowFullscreen = true;

      // Bloquear hasta que se use el primer clic
      frame.style.cssText = `
        border: none;
        background: #000;
        border-radius: 8px;
        width: 100%;
        height: 100%;
        pointer-events: ${firstClickUsed ? 'auto' : 'none'};
      `;

      containerRef.current.innerHTML = '';
      containerRef.current.appendChild(frame);

      return () => {
        if (containerRef.current) {
          containerRef.current.innerHTML = '';
        }
      };
    }
  }, [src, onError, firstClickUsed]);

  return (
    <div 
      ref={containerRef}
      className="w-full h-96 md:h-[500px] lg:h-[600px] bg-black rounded-lg relative overflow-hidden"
      style={{ 
        minHeight: '400px'
      }}
    >
      {/* Máscaras en esquinas */}
      <div className="absolute inset-0 pointer-events-none z-15">
        <div className="absolute top-0 right-0 w-32 h-24 bg-black opacity-90"></div>
        <div className="absolute top-0 left-0 w-32 h-16 bg-black opacity-90"></div>
        <div className="absolute bottom-0 left-0 right-0 h-12 bg-black opacity-90"></div>
      </div>

      {/* Botón que absorbe el primer clic malicioso */}
      {showPlayButton && (
        <div className="absolute inset-0 z-20 flex items-center justify-center bg-black bg-opacity-50">
          <button
            className="bg-red-600 hover:bg-red-700 text-white px-8 py-4 rounded-lg text-xl font-bold flex items-center gap-2"
            onClick={() => {
              console.log('Absorbiendo primer clic...');
              setFirstClickUsed(true);
              setShowPlayButton(false);
            }}
          >
            ▶️ Reproducir Video
          </button>
        </div>
      )}
    </div>
  );
};

export default VideoFrame;
